const results = $('Read Call Results').all().map(i => i.json).filter(r => r.call_id);
const leads = $('Read Leads').all().map(i => i.json).filter(l => l.phone);

if (results.length === 0) {
  return [{ json: { status: 'no_data', message: 'No calls yet', total_calls: 0 } }];
}

// Calculate stats by industry
const byIndustry = {};
const byCity = {};
const byRating = { 'high (4.5+)': {total:0,booked:0}, 'mid (3.5-4.5)': {total:0,booked:0}, 'low (<3.5)': {total:0,booked:0} };

for (const r of results) {
  if (!r.industry) continue;
  const ind = r.industry;
  const city = r.city || 'unknown';
  const isBooked = r.outcome === 'meeting_booked';
  const rating = parseFloat(r.rating) || 0;

  if (!byIndustry[ind]) byIndustry[ind] = {total:0, booked:0};
  byIndustry[ind].total++;
  if (isBooked) byIndustry[ind].booked++;

  if (!byCity[city]) byCity[city] = {total:0, booked:0};
  byCity[city].total++;
  if (isBooked) byCity[city].booked++;

  const bucket = rating >= 4.5 ? 'high (4.5+)' : rating >= 3.5 ? 'mid (3.5-4.5)' : 'low (<3.5)';
  byRating[bucket].total++;
  if (isBooked) byRating[bucket].booked++;
}

const rate = (b, t) => t > 0 ? (b/t*100).toFixed(1) + '%' : '0%';

const industryStats = Object.entries(byIndustry)
  .map(([k,v]) => ({name:k, total:v.total, booked:v.booked, rate:rate(v.booked,v.total)}))
  .sort((a,b) => parseFloat(b.rate)-parseFloat(a.rate));

const cityStats = Object.entries(byCity)
  .map(([k,v]) => ({name:k, total:v.total, booked:v.booked, rate:rate(v.booked,v.total)}))
  .sort((a,b) => parseFloat(b.rate)-parseFloat(a.rate));

// Best performers (min 3 calls)
const DEFAULT_INDUSTRIES = 'plumber,electrician,hvac contractor,roofer,painter';
const DEFAULT_CITIES = 'Austin TX,Houston TX,Dallas TX,Phoenix AZ,Las Vegas NV';

const bestIndustries = industryStats.filter(x => x.total >= 3).slice(0,5).map(x=>x.name).join(',');
const bestCities = cityStats.filter(x => x.total >= 3).slice(0,5).map(x=>x.name).join(',');

const totalCalls = results.length;
const totalBooked = results.filter(r => r.outcome==='meeting_booked').length;
const totalVoicemail = results.filter(r => r.outcome==='voicemail').length;
const totalNoAnswer = results.filter(r => r.outcome==='no_answer').length;
const totalRemoved = results.filter(r => r.outcome==='removed_from_list').length;

return [{ json: {
  total_calls: totalCalls,
  total_booked: totalBooked,
  total_voicemail: totalVoicemail,
  total_no_answer: totalNoAnswer,
  total_removed: totalRemoved,
  overall_rate: rate(totalBooked, totalCalls),
  best_industries: bestIndustries || DEFAULT_INDUSTRIES,
  best_cities: bestCities || DEFAULT_CITIES,
  industry_stats: JSON.stringify(industryStats),
  city_stats: JSON.stringify(cityStats),
  rating_stats: JSON.stringify(Object.entries(byRating).map(([k,v])=>({bucket:k,...v,rate:rate(v.booked,v.total)}))),
  week: new Date().toISOString().split('T')[0],
  data_driven: (bestIndustries.length > 0 && bestCities.length > 0) ? 'yes' : 'not yet (need 3+ calls per category)'
} }];

// Build Config tab rows from analysis results
const d = $('Analyze Performance').item.json;
return [
  { json: { key: 'target_industries', value: d.best_industries, updated_at: d.week } },
  { json: { key: 'target_cities', value: d.best_cities, updated_at: d.week } },
  { json: { key: 'overall_rate', value: d.overall_rate, updated_at: d.week } },
  { json: { key: 'total_calls', value: String(d.total_calls), updated_at: d.week } },
  { json: { key: 'data_driven', value: d.data_driven, updated_at: d.week } }
];
